  lobHeroLabel: { eng: "Virtual Reception", esp: "Recepción Virtual", ru: "Виртуальная рецепция", fr: "Réception virtuelle", it: "Reception virtuale", de: "Virtuelle Rezeption", uk: "Віртуальна рецепція", pl: "Wirtualna recepcja" },
